2053   if (!canVectorizeMemory()) {
2054     LLVM_DEBUG(dbgs() << "LV: Can't vectorize due to memory conflicts\n");
2055     if (DoExtraAnalysis)
2056       Result = false;
2057     else
2058       return false;
2059   }
2060 
2061   // Bail out for state-changing loops with uncountable exits for now.
